  ('social-worker-moex-00816', 'social-worker', 'social-worker-moex-111-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '高齡化速度增加，各類型長期照顧機構仍有人力缺口，人力高齡化亦是照顧服務產業隱憂。為彌 補人力缺口，行政院以各種積極方式提升照顧服務員社會形象，吸引照顧相關科系畢業生加入產 業。以Pincus與Minaham社會工作實務四系統分析前述狀況，下列敘述何者錯誤？', '["案主系統（clientsystem）為使用長期照顧服務長者", "標的系統（targetsystem）為照顧相關科系畢業生", "行動系統（actionsystem）主要為行政院所屬相關部會", "改變代理者系統（changeagentsystem）為機構業者、家屬與提供照顧者等"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "fcc05a79b803", "answer_pdf_sha1": "e802327f9e16", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
